function normalizeCommune(commune) {
  return commune
    .toUpperCase()
    .trim()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '') // strip accents
    .replace(/\s+CEDEX(\s+\d+)?$/i, '')               // remove CEDEX / CEDEX 01
    .replace(/-/g, ' ')                               // hyphens → spaces
    .replace(/\s+/g, ' ')                             // collapse spaces
    .trim();
}

export function getFormations(commune) {
  if (!commune) return null;
  const key = normalizeCommune(commune);
  if (formationsData[key]) return formationsData[key];
  // Fallback: try without leading article (LE/LA/LES/L')
  const noArticle = key.replace(/^(LE|LA|LES|L) /, '');
  if (noArticle !== key && formationsData[noArticle]) return formationsData[noArticle];
  return null;
}

export function getFormationsByNom(nom) {
  if (!nom) return null;
  const nomUp = nom.toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  for (const entry of Object.values(formationsData)) {
    const entryNom = entry.nom.toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
    if (entryNom === nomUp || nomUp.includes(entryNom) || entryNom.includes(nomUp)) {
      return entry;
    }
  }
  return null;
}
